func (s *Service) GetUser(ctx context.Context, id string) (User, error) {
	if id == "" {
		return User{}, fmt.Errorf("GetUser: %w", ErrInvalidID)
	}

	user, err := s.repo.FindByID(ctx, id)
	if err != nil {
		return User{}, fmt.Errorf("GetUser(%q): %w", id, err)
	}

	return user, nil
}
